module RefModule(
    input A,
    input B,
    input SEL,
    output Y
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB;
    supply0 VNB;

    wire nand1_out, nand2_out;

    // Using basic gates instead of missing library cells
    wire sel_not = ~SEL;  // Inverted SEL signal

    // NAND logic for the mux implementation
  assign Y = ~(nand1_out & nand2_out);
  assign nand2_out = ~(B & SEL);

    // Final output using NAND outputs
  assign nand1_out = ~(A & sel_not);

endmodule
